import React, { useState, useEffect } from 'react';
import { BrowserRouter, Routes, Route, Navigate, Link } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { supabase } from './supabaseClient';
import RichTextEditor from './components/RichTextEditor';
import AutoSave from './components/AutoSave';
import UserRoleBadge from './components/UserRoleBadge';
import TrendingTicker from './components/TrendingTicker';
import StatisticsPage from './components/StatisticsPage';
import './App.css';

// ==================== LOGIN COMPONENT ====================
function Login({ onLogin }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    const { data, error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) setError(error.message);
    else onLogin(data.user);
    setLoading(false);
  };

  return (
    <div className="split-screen">
      <div className="split-gallery">
        <div className="gallery-overlay">
          <div className="presidential-seal"></div>
          <h1>Réforme Constitutionnelle</h1>
          <h2>Consultation Nationale</h2>
          <div className="hero-quote">"La voix de 80 millions de Congolais"</div>
        </div>
        <div className="gallery-carousel"></div>
      </div>
      <div className="split-form">
        <div className="form-container glass-morphism">
          <img src="/images/logo-presidence-rdc.png" alt="Présidence RDC" className="form-logo" />
          <h2>Connexion</h2>
          <p className="form-subtitle">Espace citoyen sécurisé</p>
          {error && <div className="error-message">{error}</div>}
          <form onSubmit={handleSubmit}>
            <div className="input-group">
              <label>Email</label>
              <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} required />
            </div>
            <div className="input-group">
              <label>Mot de passe</label>
              <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} required />
            </div>
            <button type="submit" disabled={loading} className="btn-gold">
              {loading ? 'Connexion...' : 'Accéder à mon espace'}
            </button>
          </form>
          <p className="form-footer">
            Pas encore de compte ? <Link to="/signup">Créer un compte</Link>
          </p>
        </div>
      </div>
    </div>
  );
}

// ==================== SIGNUP COMPONENT ====================
function Signup({ onSignup }) {
  const [formData, setFormData] = useState({
    email: '', password: '', fullName: '', province: '', role: 'citizen', phone: ''
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const provinces = ['Kinshasa', 'Kongo Central', 'Haut-Katanga', 'Nord-Kivu', 'Sud-Kivu', 'Équateur', 'Mongala', 'Tshopo', 'Kasaï', 'Lualaba', 'Maniema', 'Ituri', 'Haut-Lomami', 'Tanganyika', 'Lomami', 'Sankuru'];

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    const { data, error } = await supabase.auth.signUp({
      email: formData.email,
      password: formData.password,
      options: { data: { full_name: formData.fullName, province: formData.province, role: formData.role, phone: formData.phone } }
    });
    if (error) setError(error.message);
    else if (data.user) {
      await supabase.from('profiles').insert([{
        id: data.user.id,
        email: formData.email,
        full_name: formData.fullName,
        province: formData.province,
        role: formData.role,
        phone: formData.phone
      }]);
      onSignup(data.user);
    }
    setLoading(false);
  };

  return (
    <div className="split-screen">
      <div className="split-gallery">
        <div className="gallery-overlay">
          <div className="presidential-seal"></div>
          <h1>Devenir acteur du changement</h1>
          <h2>Inscrivez-vous</h2>
        </div>
      </div>
      <div className="split-form">
        <div className="form-container glass-morphism">
          <h2>Créer mon compte</h2>
          <p className="form-subtitle">Identité citoyenne</p>
          {error && <div className="error-message">{error}</div>}
          <form onSubmit={handleSubmit}>
            <div className="input-group">
              <label>Nom complet</label>
              <input type="text" value={formData.fullName} onChange={(e) => setFormData({ ...formData, fullName: e.target.value })} required />
            </div>
            <div className="input-group">
              <label>Email</label>
              <input type="email" value={formData.email} onChange={(e) => setFormData({ ...formData, email: e.target.value })} required />
            </div>
            <div className="input-group">
              <label>Téléphone</label>
              <input type="tel" value={formData.phone} onChange={(e) => setFormData({ ...formData, phone: e.target.value })} />
            </div>
            <div className="input-group">
              <label>Province</label>
              <select value={formData.province} onChange={(e) => setFormData({ ...formData, province: e.target.value })} required>
                <option value="">Sélectionnez</option>
                {provinces.map(p => <option key={p} value={p}>{p}</option>)}
              </select>
            </div>
            <div className="input-group">
              <label>Catégorie</label>
              <select value={formData.role} onChange={(e) => setFormData({ ...formData, role: e.target.value })}>
                <option value="citizen">Citoyen</option>
                <option value="political_party">Parti politique</option>
                <option value="civil_society">Société civile</option>
              </select>
            </div>
            <div className="input-group">
              <label>Mot de passe (min. 6 caractères)</label>
              <input type="password" value={formData.password} onChange={(e) => setFormData({ ...formData, password: e.target.value })} required />
            </div>
            <button type="submit" disabled={loading} className="btn-gold">{loading ? 'Inscription...' : 'Créer mon compte'}</button>
          </form>
          <p className="form-footer">Déjà inscrit ? <Link to="/login">Se connecter</Link></p>
        </div>
      </div>
    </div>
  );
}

