// ==================== DASHBOARD – PROPOSAL SUBMISSION ====================
function Dashboard({ user }) {
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [category, setCategory] = useState('');
  const [files, setFiles] = useState([]);
  const [proposals, setProposals] = useState([]);
  const [message, setMessage] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [profile, setProfile] = useState(null);

  useEffect(() => {
    fetchProfile();
    fetchProposals();
  }, []);

  const fetchProfile = async () => {
    const { data } = await supabase.from('profiles').select('*').eq('id', user.id).single();
    if (data) setProfile(data);
  };

  const fetchProposals = async () => {
    const { data } = await supabase.from('proposals').select('*').order('created_at', { ascending: false });
    if (data) setProposals(data);
  };

  const uploadImages = async () => {
    const urls = [];
    for (const file of files) {
      const fileName = `${Date.now()}-${file.name}`;
      const { error } = await supabase.storage.from('proposal-images').upload(fileName, file);
      if (!error) {
        const { data: { publicUrl } } = supabase.storage.from('proposal-images').getPublicUrl(fileName);
        urls.push(publicUrl);
      }
    }
    return urls;
  };

  const saveDraft = async (data) => {
    localStorage.setItem('proposal-draft', JSON.stringify(data));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    setMessage('');
    const imageUrls = await uploadImages();
    const { error } = await supabase.from('proposals').insert([{
      user_id: user.id,
      title,
      content,
      category,
      image_urls: imageUrls,
      status: 'pending'
    }]);
    if (error) setMessage('Erreur: ' + error.message);
    else {
      setMessage('Proposition soumise avec succès !');
      setTitle('');
      setContent('');
      setCategory('');
      setFiles([]);
      localStorage.removeItem('proposal-draft');
      fetchProposals();
    }
    setSubmitting(false);
  };

  return (
    <div className="dashboard-modern">
      <div className="dashboard-container">
        <div className="proposal-section">
          <div className="section-card">
            <div className="card-header-premium">
              <h2>Soumettre une proposition</h2>
              <p>Partagez votre vision pour la réforme constitutionnelle</p>
            </div>
            {message && <div className="success-message">{message}</div>}
            <form onSubmit={handleSubmit}>
              <div className="input-group">
                <label>Titre de la proposition</label>
                <input type="text" value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Ex: Réforme du mandat présidentiel" required />
              </div>
              <div className="input-group">
                <label>Catégorie</label>
                <select value={category} onChange={(e) => setCategory(e.target.value)} required>
                  <option value="">Sélectionnez</option>
                  <option value="Gouvernance">Gouvernance</option>
                  <option value="Justice">Justice</option>
                  <option value="Élections">Élections</option>
                  <option value="Décentralisation">Décentralisation</option>
                  <option value="Droits humains">Droits humains</option>
                  <option value="Économie">Économie</option>
                </select>
              </div>
              <div className="input-group">
                <label>Contenu détaillé</label>
                <RichTextEditor value={content} onChange={setContent} />
              </div>
              <div className="input-group">
                <label>Documents joints (images)</label>
                <input type="file" multiple accept="image/*" onChange={(e) => setFiles(Array.from(e.target.files))} />
              </div>
              <button type="submit" disabled={submitting} className="btn-gold btn-full">
                {submitting ? 'Soumission...' : 'Soumettre la proposition'}
              </button>
            </form>
            <AutoSave data={{ title, content, category }} onSave={saveDraft} interval={15000} />
          </div>
        </div>

        <div className="feed-section">
          <div className="section-card">
            <div className="card-header-premium">
              <h3>Propositions récentes</h3>
              <p>Contributions des citoyens</p>
            </div>
            <div className="proposals-feed">
              {proposals.map(p => (
                <div key={p.id} className="feed-card">
                  <div className="feed-header">
                    <div className="user-info">
                      <div className="user-avatar">👤</div>
                      <div>
                        <div className="user-name">{profile?.full_name || 'Citoyen'}</div>
                        {profile && <UserRoleBadge role={profile.role} />}
                      </div>
                    </div>
                    <div className="category-tag">{p.category}</div>
                  </div>
                  <h4>{p.title}</h4>
                  <div className="feed-excerpt" dangerouslySetInnerHTML={{ __html: p.content.substring(0, 200) + '...' }} />
                  {p.image_urls && p.image_urls[0] && <img src={p.image_urls[0]} alt="Aperçu" className="feed-image" />}
                  <div className="feed-footer">
                    <button className="support-button">🤝 Soutenir</button>
                    <span className="support-count">0 signatures</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ==================== MAIN APP ====================
function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user || null);
      setLoading(false);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user || null);
    });
    return () => subscription.unsubscribe();
  }, []);

  if (loading) return <div className="loading-screen"><div className="loader"></div><p>Portail sécurisé</p></div>;

  return (
    <BrowserRouter>
      <nav className="navbar-premium">
        <div className="nav-container">
          <Link to="/" className="nav-brand">
            <img src="/images/logo-presidence-rdc.png" alt="Présidence RDC" className="nav-logo" />
            <span>RDC | Réforme Constitutionnelle</span>
          </Link>
          <div className="nav-links">
            <Link to="/">Accueil</Link>
            <Link to="/statistics">Analyses</Link>
            {user && <Link to="/dashboard">Soumettre</Link>}
            {user ? (
              <button onClick={() => supabase.auth.signOut()} className="nav-outline">Déconnexion</button>
            ) : (
              <Link to="/login" className="btn-nav">Connexion</Link>
            )}
          </div>
        </div>
      </nav>
      <Routes>
        <Route path="/" element={<Homepage user={user} />} />
        <Route path="/statistics" element={<StatisticsPage />} />
        <Route path="/login" element={user ? <Navigate to="/dashboard" /> : <Login onLogin={setUser} />} />
        <Route path="/signup" element={user ? <Navigate to="/dashboard" /> : <Signup onSignup={setUser} />} />
        <Route path="/dashboard" element={user ? <Dashboard user={user} /> : <Navigate to="/login" />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
